```

**Lambda Redrive (~50 linhas):**

```typescript
import { SQSClient, StartMessageMoveTaskCommand } from '@aws-sdk/client-sqs';

const DLQ_ARN = process.env.DLQ_ARN!;
const sqs = new SQSClient({ region: 'sa-east-1' });

export async function handler() {
  // Verificar se CBILL está acessível (health check simples)
  const cbillHealthy = await checkCBILLHealth();
  if (!cbillHealthy) {
    console.log('CBILL indisponível - adiando redrive');
    return { statusCode: 200, body: 'Skipped - CBILL unavailable' };
  }

  const result = await sqs.send(new StartMessageMoveTaskCommand({
    SourceArn: DLQ_ARN,
    MaxNumberOfMessagesPerSecond: 5  // Rate limit para não sobrecarregar CBILL
  }));

  console.log('Redrive iniciado:', result.TaskHandle);
  return { statusCode: 200, body: JSON.stringify(result) };
}

async function checkCBILLHealth(): Promise<boolean> {
  try {
    // Health check leve - apenas verifica conectividade
    const response = await fetch(`http://${process.env.CBILL_HOST}/health`, {
      method: 'HEAD',
      timeout: 5000
    });
    return response.ok;
  } catch {
    return false;
  }
}
```

**Trigger:** EventBridge Scheduler (a cada 30 minutos) ou CloudWatch Alarm quando DLQ depth > threshold.

**Custo:** ~$0.50/mês

