import { GraphQlService } from "libAppCommons";
import { AccountFilter } from "../infrastructure/index";
import { CustomerFilterResponse } from "../models/index";

export class GetUserNRC {
    constructor(private readonly graphQlService: GraphQlService) {}

  async execute(
    companyIdentification: string,
    customerIdentification: string
  ): Promise<string> {
    const parameters = [companyIdentification, customerIdentification];

    try {
      const response: CustomerFilterResponse = await this.graphQlService.executeQuery(
        process.env.NST_BILLING_CUSTOMER_URL!,
        process.env.NST_BILLING_PORT!,
        AccountFilter,
        parameters,
        process.env.NST_BILLING_PATH!
      );

      if (response.status == -1) {
        throw new Error(response.error);
      }

      if(response?.data?.data?.customerFilter.customer === null){
        throw new Error("Customer not found");
      }


      return response?.data?.data?.customerFilter.customer[0].companyAssociations[0].nrc;
    } catch (err) {
      throw new Error(String('BillingCustomerService.customerFilter' + err));
    }
  }
}

