import { LogType } from "./Utils/customError";

export type HeaderCrypto = {
    uuid: string | number;
    devicename: string | number;
    empresa: string | number;
    lat: string | number;
};

export class Crypto {
    static generatePIN(): { pass: string, hash: string };
    static generateHashWithDate(request: any, headers: HeaderCrypto): string;
    static generateHashWithoutDate(request: any, headers: HeaderCrypto): string;
    static validateHashWithoutDate(hash: string, event: { data: any, headers: HeaderCrypto }): boolean;
    static encryptData(data: any): string;
    static decryptData(data: string): any;
}

export class TokenService {
    /**
     * @param params.TableName - The name of the table on DynamoDB
     */
    constructor(params: { TableName: string }) { }

    saveToken(cpf: string | number, temporaryToken: string | number, expireTime: string | number, actionId?: string | number, attemptCount?: number): Promise<any>;
    getToken(cpf: string | number): Promise<any>;
    removeToken(cpf: string | number): Promise<any>;

    /**
     * Call getToken and validate if the pin is correct
     * Remove pin if prop.removeToken is true
     */
    validateToken(obj: { document: string | number, pin: string | number, actionId: string | number }, prop?: { removeToken: boolean }): Promise<boolean>;
}

export class Adapter {
    static getAccountResponse(customer: CustomerGraphQL, account: AccountGraphQL): AccountResponse;
    static getCustomerResponse(customer: CustomerGraphQL, account: AccountGraphQL): CustomerResponse;
}

export class Query {
    static getQueryCustomerAccout(): RequestGraphQL;
}

export class GraphQlService {
    executeQuery(
        host: string, port: string,
        query: RequestGraphQL, parameters: any[], path: string = '')
        : Promise<GraphQlResponse>;

    static queryFilter(object: Object | null): string;
}

export class Callback {
    constructor(eventAws: any, callbackAws: any, context: any);
    send(erro: { status: { [x: string]: any; }; } | null, detail?: any): void;
}

export class Util {
    static getCustomerSituation(dunningSendIndicator: string, dunningType: number): CustomerSituation;
    static executeTestCase<D = any, E = any>(execute: (event: any, context: null, callback: any) => Promise<void>, body: any): Promise<{ err: E, data: D; }>;
    static getIsoDataAtual(): string;
    static getIsoDataAtualFormat(): string;
    static convertDateBRtoDate(dateSaoPaulo: any): Date;
    static subtrairDias(data: any, dias: any): string;
    static getDate(): string;
    static getDataAtualSaoPaulo(): Date;
    static convertIsoDateToSaoPaulo(dateIso: any): string;
    static convertDateAsNumber(dateSaoPaulo: any): number;
}

export type Headers = {
    empresa: string | number;
    codigocliente: string | number;
};

export type Env = {
    ocpHost: string;
    ocpPort: string;
};

export class CustomerAccount {
    getCustomerAndAccount(event: { headers: Headers; env: Env}): Promise<CustomerAccountResponse>;
    getCustomerAndAccountFromCustomerCloud(event: { headers: Headers; env: Env}): Promise<CustomerAccountResponse>;
    getCustomerAndAccount(event: { headers: Headers; env: Env }): Promise<CustomerAccountResponse>;
}

export class CustomerSituation {
    constructor(id: number, desc: string);
}

export type GraphQlResponse = {
    status: number,
    data: any,
    error: string;
};

export type CustomerAccountGraphQlResponse = {
    status: number,
    data: CustomerFilterAccountFilterGraphQL,
    error: string;
};

export type CustomerFilterAccountFilterGraphQL = {
    data: CustomerAccountFilterGraphQL,
    errors?: any[],
};

export type CustomerAccountFilterGraphQL = {
    accountFilter?: AccountFilterGraphQL,
    customerFilter?: CustomerFilterGraphQL;
};

export type AccountFilterGraphQL = {
    accounts: [AccountGraphQL];
};

export type CustomerFilterGraphQL = {
    customer: [CustomerGraphQL];
};

export type CustomerGraphQL = {
    name: string,
    gender: number,
    maritalStatusIdentification: number,
    birthday: string,
    mainDocument: MainDocumentGraphQL,
    auxiliaryDocuments: [AuxiliaryDocumentGraphQL],
    customerAddresses: [CustomerAddressGraphQL],
    customerContacts: CustomerContactsGraphQL,
    companyAssociations: [CompanyAssociationGraphQL],
    collectionAdvisory: CollectionAdvisoryGraphQL,
};

export type MainDocumentGraphQL = {
    acronymType: string,
    value: string,
};

export type AuxiliaryDocumentGraphQL = {
    acronymType: string,
    value: string,
};

export type CustomerAddressGraphQL = {
    label: string,
    principal: string,
    address: AddressGraphQL,
};

export type AddressGraphQL = {
    identification: string,
    stateIdentification: string,
    stateName: string,
    stateAcronym: string,
    cityName: string,
    number: number,
    complement: string,
    superDivisionName: string,
    addressStreet: AddressStreetGraphQL,
    zipCode: string,
};

export type AddressStreetGraphQL = {
    name: string,
};

export type CustomerContactsGraphQL = {
    customerContact: [CustomerContactGraphQL],
};

export type CustomerContactGraphQL = {
    customerIdentification: string,
    principal: string,
    contactModesValue: ContactModeValueGraphQL,
};

export type ContactModeValueGraphQL = {
    contactModeValue: [ContactModeValueObjGraphQL],
};

export type ContactModeValueObjGraphQL = {
    contactModeIdentification: string,
    value: string,
    preferential: string
};

export type CompanyAssociationGraphQL = {
    situation: number,
    activationDate: string,
